private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal SettedEggs = 0;
decimal RejSellEggs = 0;
decimal RejUnSellEggs = 0;

if (GetCurrentColumnValue("SettedEggs") != null)
    SettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

if (GetCurrentColumnValue("RejSellEggs") != null)
    RejSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejSellEggs"));

if (GetCurrentColumnValue("RejUnSellEggs") != null)
    RejUnSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejUnSellEggs"));

settedEggsRejSelableGroup +=  SettedEggs ;
rejSellEggsGroup += RejSellEggs ;
rejUnSellEggsGroup += RejUnSellEggs ;
SettedAndRejEggsTotalGroup = settedEggsRejSelableGroup + rejSellEggsGroup + rejUnSellEggsGroup ;
if (SettedAndRejEggsTotalGroup > 0)
    SettedAndRejEggsTotal = (rejSellEggsGroup / SettedAndRejEggsTotalGroup ) * 100;
   //-- new logic for unSellableEggs
if (SettedAndRejEggsTotalGroup > 0)
    SettedAndRejUnSelableEggsTotal = SettedAndRejEggsTotalGroup ;

   //-- new logic for Infertile Eggs
    // --- Declare variables ---
    decimal infertileEggs = 0;
    decimal SettedEggsinfertileEggs   = 0;
    // --- Read values safely ---
    if (GetCurrentColumnValue("SettedEggs") != null)
    SettedEggsinfertileEggs  = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    if (GetCurrentColumnValue("InfertileEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("InfertileEggs").ToString()))
    {
        infertileEggs = Convert.ToDecimal(GetCurrentColumnValue("InfertileEggs"));
    }

    // --- Equation (same as Iif([SettedEggs] > 0, [InfertileEggs] / [SettedEggs] * 100, 0)) ---
    settedEggsInfertileEggsGroup +=  SettedEggsinfertileEggs  ;
    InfertileEggsGroup += infertileEggs ;
    if (settedEggsInfertileEggsGroup > 0)
        InfertileEggsTotal =  (InfertileEggsGroup  * 100m) / settedEggsInfertileEggsGroup ;

        //-- new logic for NonHat Eggs
    // --- Declare variables ---
    decimal NonHatEggs = 0;
    decimal NonHatEggsSettedEggs  = 0;
    decimal NonHatEggsRejSellEggs  = 0;
    decimal NonHatEggsRejUnSellEggs  = 0;
    // --- Read values safely ---
    if (GetCurrentColumnValue("SettedEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
    {
        NonHatEggsSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
    }
    if (GetCurrentColumnValue("RejSellEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("RejSellEggs").ToString()))
    {
        NonHatEggsRejSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejSellEggs"));
    }
    if (GetCurrentColumnValue("RejUnSellEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("RejUnSellEggs").ToString()))
    {
        NonHatEggsRejUnSellEggs = Convert.ToDecimal(GetCurrentColumnValue("RejUnSellEggs"));
    }

    if (GetCurrentColumnValue("NonHatEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("NonHatEggs").ToString()))
    {
        NonHatEggs = Convert.ToDecimal(GetCurrentColumnValue("NonHatEggs"));
    }
    NonHatEggsSettedEggsGroup += NonHatEggsSettedEggs ;
    NonHatEggsRejSellEggsGroup += NonHatEggsRejSellEggs ;
    NonHatEggsRejUnSellEggsGroup += NonHatEggsRejUnSellEggs ;
    NonHatEggsGroup += NonHatEggs ;
    TotaalSettedRejEggsGroup = NonHatEggsSettedEggsGroup  + NonHatEggsRejSellEggsGroup  + NonHatEggsRejUnSellEggsGroup ;
    // --- Equation (same as Iif([SettedEggs] > 0, [NonHatEggs] / [SettedEggs] * 100, 0)) ---
    if (NonHatEggsSettedEggsGroup > 0)
    {
        NonHatEggsTotal =  (NonHatEggsGroup * 100m)/ TotaalSettedRejEggsGroup ;

    }
    else
    {
        NonHatEggsTotal = 0;
    }

       //-- new logic for Total Chicks (Culls + SellableChicks)
        // --- Declare variables ---
        decimal culls = 0;
        decimal sellableChicks = 0;
        decimal result4 = 0;

        // --- Read values safely ---
        if (GetCurrentColumnValue("Culls") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("Culls").ToString()))
        {
            culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));
        }

        if (GetCurrentColumnValue("SellableChicks") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("SellableChicks").ToString()))
        {
            sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));
        }

        // --- Equation (same as [Culls] + [SellableChicks]) ---
        result4 = culls + sellableChicks;

        // --- Optional: accumulate total ---
        totalCullsAndSellableChicks += result4;
        //-- new logic for Deads Eggs
        decimal deadsSettedEggs  = 0;
        decimal deads = 0;
        decimal deadRatio = 0;

        // --- Read values safely ---
        if (GetCurrentColumnValue("SettedEggs") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
        {
            deadsSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        }

        if (GetCurrentColumnValue("Deads") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("Deads").ToString()))
        {
            deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));
        }
        deadsSettedEggsGroup += deadsSettedEggs ;
        deadsGroup += deads  ;
        // --- Equation (same as Iif([SettedEggs] > 0, [Deads] / [SettedEggs], 0)) ---
        if (deadsSettedEggsGroup > 0)
        {
            deadRatio = (deadsGroup * 100m)/ deadsSettedEggsGroup ;
        }
        else
        {
            deadRatio = 0;
        }

        // --- Optional: accumulate total ---

        totalDeadRatioReport = deadRatio;
            //-- new logic for Culls Ratio (Culls / SettedEggs)
        // --- Declare variables ---
        decimal CullsSettedEggs  = 0;
        // --- Read values safely ---
        if (GetCurrentColumnValue("SettedEggs") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
        {
            CullsSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        }

        if (GetCurrentColumnValue("Culls") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("Culls").ToString()))
        {
            culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));
        }

        // --- Equation (same as Iif([SettedEggs] > 0, [Culls] / [SettedEggs], 0)) ---
        CullsSettedEggsGroup += CullsSettedEggs ;
        cullsGroup += culls ;
        if (CullsSettedEggsGroup > 0)
        {
            totalCullsRatio =  (cullsGroup * 100m) / CullsSettedEggsGroup ;  
                    }
        else
        {
            totalCullsRatio = 0;
        }

        // --- Optional: accumulate total ---

            //-- new logic for Sellable Chicks Ratio (SellableChicks / SettedEggs)
        // --- Declare variables ---
        decimal sellableChicksSettedEggs  = 0;
        // --- Read values safely ---
        if (GetCurrentColumnValue("SettedEggs") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
        {
            sellableChicksSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        }

        if (GetCurrentColumnValue("SellableChicks") != null &&
            !string.IsNullOrEmpty(GetCurrentColumnValue("SellableChicks").ToString()))
        {
            sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));
        }

        // --- Equation (same as Iif([SettedEggs] > 0, [SellableChicks] / [SettedEggs], 0)) ---
        sellableChicksSettedEggsGroup  += sellableChicksSettedEggs ;
        sellableChicksGroup += sellableChicks ;
        if (sellableChicksSettedEggsGroup  > 0)
        {
            totalSellableRatio = (sellableChicksGroup * 100m) / sellableChicksSettedEggsGroup  ;
        }
        else
        {
            totalSellableRatio = 0;
        }
    //-- new logic for Total Chicks Ratio ((Culls + SellableChicks) / SettedEggs)
// --- Declare variables ---
decimal totalRatio = 0;
decimal TotalChicksRatioSettedEggs  = 0;
decimal TotalChicksRatioCulls = 0;
decimal TotalChicksRatioSellableChicks  = 0;
decimal TotalChicksRatioFertileEggs  = 0;
// --- Read values safely ---
if (GetCurrentColumnValue("SettedEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
{
    TotalChicksRatioSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
}

if (GetCurrentColumnValue("Culls") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("Culls").ToString()))
{
    TotalChicksRatioCulls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));
}

if (GetCurrentColumnValue("SellableChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SellableChicks").ToString()))
{
    TotalChicksRatioSellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));
}
if (GetCurrentColumnValue("FertileEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("FertileEggs").ToString()))
{
    TotalChicksRatioFertileEggs = Convert.ToDecimal(GetCurrentColumnValue("FertileEggs"));
}

// --- Equation (same as Iif([SettedEggs] > 0, ([Culls] + [SellableChicks]) / [SettedEggs], 0)) ---
TotalChicksRatioSettedEggsGroup += TotalChicksRatioSettedEggs ;
TotalChicksRatiocullsGroup +=  TotalChicksRatioCulls ;
TotalChicksRatioSellableChicksGroup += TotalChicksRatioSellableChicks  ;
TotalChicksRatioFertileEggsGroup += TotalChicksRatioFertileEggs ;

if (TotalChicksRatioSettedEggsGroup > 0)
{
    totalRatio = ((TotalChicksRatiocullsGroup + TotalChicksRatioSellableChicksGroup ) * 100m)/ TotalChicksRatioSettedEggsGroup ;
}
else
{
    totalRatio = 0;
}

// --- Optional: accumulate total ---
totalChicksRatio = totalRatio;
    // -- New Logic for Sellable Chicks Percentage --

// --- Declare variables ---
decimal SellablePercSettedEggs = 0 ;
decimal sellableChicksPercSellableChicks = 0;
decimal SellablePerc = 0 ;
// --- Read values safely ---
if (GetCurrentColumnValue("SettedEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
{
    SellablePercSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
}

if (GetCurrentColumnValue("SellableChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SellableChicks").ToString()))
{
    sellableChicksPercSellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));
}

// --- Perform calculation ---
SellablePercSettedEggsGroup += SellablePercSettedEggs ;
sellableChicksPercGroup += sellableChicksPercSellableChicks ;
if (SellablePercSettedEggsGroup > 0)
{
    SellablePerc = (sellableChicksPercGroup * 100m) / SellablePercSettedEggsGroup ;
}
else
{
    SellablePerc = 0;
}
SaleFertile  = SellablePerc ;

//New Logic for AllSetted Hatchibilty
TotalAllSettedEggs = TotalChicksRatiocullsGroup  + TotalChicksRatioSellableChicksGroup ;
if(TotalChicksRatioSettedEggsGroup  > 0){

    TotalAllSettedEggsGroup = (TotalAllSettedEggs * 100m) / TotalChicksRatioSettedEggsGroup  ;
 }


//New Logic for Sale / Fertile Hatchibilty
if(TotalChicksRatioFertileEggsGroup> 0){

    TotalSaleFertileGroup = (TotalChicksRatioSellableChicksGroup * 100m) / TotalChicksRatioFertileEggsGroup;
 }


}


