private void xrTableCell20_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      // --- Declare values ---
    decimal settedEggs = 0;
    decimal infertileEggs = 0;

    // --- Read values safely ---
    if (GetCurrentColumnValue("SettedEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
    {
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
    }

    if (GetCurrentColumnValue("InfertileEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("InfertileEggs").ToString()))
    {
        infertileEggs = Convert.ToDecimal(GetCurrentColumnValue("InfertileEggs"));
    }

    // --- Equation ---
    decimal result = 0;
    if (settedEggs > 0){
         result = (infertileEggs / settedEggs) * 100;
        }

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N2"); // format with 2 decimals
    infertileEggsReport +=  infertileEggs ;
    settedEggsInfertileReport += settedEggs ;

}

