private void xrTableCell11_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Declare variables ---
decimal settedEggs = 0;
decimal NonHatEggs = 0;
decimal result = 0;
decimal RejSellEggsNonHat  =0;
decimal RejUnSellEggsNonHat  = 0;
// --- Read values safely ---
if (GetCurrentColumnValue("SettedEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("SettedEggs").ToString()))
{
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
}
if (GetCurrentColumnValue("RejSellEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejSellEggs").ToString()))
{
    RejSellEggsNonHat = Convert.ToDecimal(GetCurrentColumnValue("RejSellEggs"));
}

if (GetCurrentColumnValue("RejUnSellEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RejUnSellEggs").ToString()))
{
    RejUnSellEggsNonHat = Convert.ToDecimal(GetCurrentColumnValue("RejUnSellEggs"));
}

if (GetCurrentColumnValue("NonHatEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("NonHatEggs").ToString()))
{
    NonHatEggs = Convert.ToDecimal(GetCurrentColumnValue("NonHatEggs"));
}

// --- Equation (same as Iif([SettedEggs] > 0, [FertileEggs] / [SettedEggs], 0)) ---
decimal SettedRejTotal = settedEggs  + RejSellEggsNonHat  + RejUnSellEggsNonHat ;
if (SettedRejTotal > 0){

        result = (NonHatEggs / SettedRejTotal ) * 100;   // multiply by 100 if you want percentage

    }
else{
        result = 0;

    }

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");   // format with 2 decimal places
}

